-- -----------------------------------------------------
-- Schema am_abisleri
-- -----------------------------------------------------
DROP SCHEMA IF EXISTS am_abisleri;
CREATE SCHEMA IF NOT EXISTS am_abisleri DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci;
USE am_abisleri;

-- -----------------------------------------------------
-- Table am_abisleri.Educational_Institute
-- -----------------------------------------------------
CREATE TABLE IF NOT EXISTS am_abisleri.Educational_Institute (
  Institute_ID INT NOT NULL,
  Name VARCHAR(45) NOT NULL,
  Ranking INT NULL,
  Courses VARCHAR(45) NOT NULL,
  Intake VARCHAR(45) NOT NULL,
  PRIMARY KEY (Institute_ID))
ENGINE = InnoDB;

-- -----------------------------------------------------
-- Table am_abisleri.Complaint
-- -----------------------------------------------------
CREATE TABLE IF NOT EXISTS am_abisleri.Complaint (
  Complaint_ID INT NOT NULL,
  Description VARCHAR(500) NOT NULL,
  Date DATE NOT NULL,
  Status VARCHAR(45) NOT NULL,
  Process_time INT NULL,
  PRIMARY KEY (Complaint_ID))
ENGINE = InnoDB;

-- -----------------------------------------------------
-- Table am_abisleri.Public_Service
-- -----------------------------------------------------
CREATE TABLE IF NOT EXISTS am_abisleri.Public_Service (
  Public_Service_ID INT NOT NULL,
  Type VARCHAR(45) NOT NULL,
  Date_time DATETIME NOT NULL,
  First_Name VARCHAR(45) NOT NULL,
  Last_Name VARCHAR(45) NOT NULL,
  PRIMARY KEY (Public_Service_ID))
ENGINE = InnoDB;

-- -----------------------------------------------------
-- Table am_abisleri.Event
-- -----------------------------------------------------
CREATE TABLE IF NOT EXISTS am_abisleri.Event (
  Event_ID INT NOT NULL,
  Type VARCHAR(45) NOT NULL,
  Artist VARCHAR(45) NULL,
  Population INT NULL,
  Seasons VARCHAR(45) NULL,
  Price INT NULL,
  Location VARCHAR(45) NOT NULL,
  IsResident TINYINT(1) NULL,
  Tax INT NOT NULL,
  PRIMARY KEY (Event_ID))
ENGINE = InnoDB;

-- -----------------------------------------------------
-- Table am_abisleri.Resident
-- -----------------------------------------------------
CREATE TABLE IF NOT EXISTS am_abisleri.Resident (
  Resident_ID VARCHAR(45) NOT NULL,
  First_Name VARCHAR(45) NOT NULL,
  Last_Name VARCHAR(45) NOT NULL,
  SSN INT NULL,
  DoB DATE NOT NULL,
  Income FLOAT NULL,
  Gender CHAR(1) NULL,
  Tax DECIMAL NULL,
  University_University_ID INT NOT NULL,
  Complaints_Complaint_ID INT NULL,
  Public_Service_Public_Service_ID INT NULL,
  Event_Event_ID INT NULL,
  PRIMARY KEY (Resident_ID),
  CONSTRAINT fk_Resident_University
    FOREIGN KEY (University_University_ID)
    REFERENCES am_abisleri.Educational_Institute (Institute_ID)
    ON DELETE NO ACTION
    ON UPDATE NO ACTION,
  CONSTRAINT fk_Resident_Complaints
    FOREIGN KEY (Complaints_Complaint_ID)
    REFERENCES am_abisleri.Complaint (Complaint_ID)
    ON DELETE NO ACTION
    ON UPDATE NO ACTION,
  CONSTRAINT fk_Resident_Public_Service
    FOREIGN KEY (Public_Service_Public_Service_ID)
    REFERENCES am_abisleri.Public_Service (Public_Service_ID)
    ON DELETE NO ACTION
    ON UPDATE NO ACTION,
  CONSTRAINT fk_Resident_Event
    FOREIGN KEY (Event_Event_ID)
    REFERENCES am_abisleri.Event (Event_ID)
    ON DELETE NO ACTION
    ON UPDATE NO ACTION)
ENGINE = InnoDB;

-- -----------------------------------------------------
-- Table am_abisleri.Bank
-- -----------------------------------------------------
CREATE TABLE IF NOT EXISTS am_abisleri.Bank (
  Bank_ID VARCHAR(45) NOT NULL,
  Acc_No BIGINT NOT NULL,
  Date DATE NULL,
  Inflow INT NULL,
  Outflow INT NULL,
  Resident_Resident_ID VARCHAR(45) NOT NULL,
  PRIMARY KEY (Bank_ID),
  CONSTRAINT fk_Bank_Resident
    FOREIGN KEY (Resident_Resident_ID)
    REFERENCES am_abisleri.Resident (Resident_ID)
    ON DELETE NO ACTION
    ON UPDATE NO ACTION)
ENGINE = InnoDB;

-- -----------------------------------------------------
-- Table am_abisleri.Public_Transport
-- -----------------------------------------------------

CREATE TABLE IF NOT EXISTS am_abisleri.Public_Transport (
  `Vehicle_ID` INT NOT NULL,
  `Distance` INT NULL,
  `Date` DATE NOT NULL,
  `Price` INT NULL,
  `Delay Time` INT NULL,
  `Start time` datetime NULL,
  `End time` datetime NULL,
  `Transport Mode` VARCHAR(45) NOT NULL,
  `IsDelay` BINARY NULL,
  PRIMARY KEY (`Vehicle_ID`))
ENGINE = InnoDB;

-- -----------------------------------------------------
-- Table am_abisleri.Business
-- -----------------------------------------------------

CREATE TABLE IF NOT EXISTS am_abisleri.Business (
  `Business_ID` INT NOT NULL,
  `Type` VARCHAR(45) NOT NULL,
  `Revenue` INT NULL,
  `Start Year` DATE NOT NULL,
  `Tax` INT NOT NULL,
  PRIMARY KEY (`Business_ID`))
ENGINE = InnoDB;


-- -----------------------------------------------------
-- Table am_abisleri.Residence
-- -----------------------------------------------------
CREATE TABLE IF NOT EXISTS am_abisleri.Residence (
  Residence_ID VARCHAR(20) NOT NULL,
