-- -----------------------------------------------------
-- Table am_abisleri.Tourist
-- -----------------------------------------------------
CREATE TABLE IF NOT EXISTS am_abisleri.Tourist (
  `Tourist ID` INT NOT NULL,
  `First Name` VARCHAR(45) NOT NULL,
