  `Event_Event ID` INT NULL,
  PRIMARY KEY (`Tourist ID`),
  INDEX `fk_Tourism_Event1_idx` (`Event_Event ID` ASC) VISIBLE,
  CONSTRAINT `fk_Tourism_Event1`
    FOREIGN KEY (`Event_Event ID`)
    REFERENCES am_abisleri.Event(Event_ID)
    ON DELETE NO ACTION
    ON UPDATE NO ACTION)
ENGINE = InnoDB;


-- -----------------------------------------------------
-- Table am_abisleri.Weather
-- -----------------------------------------------------
CREATE TABLE IF NOT EXISTS am_abisleri.Weather (
