  `IsPaid` BINARY NOT NULL,
  PRIMARY KEY (`Amenity_ID`))
ENGINE = InnoDB;

-- -----------------------------------------------------
-- Table am_abisleri.Resident_has_Business
-- -----------------------------------------------------
CREATE TABLE IF NOT EXISTS am_abisleri.Resident_has_Business (
