    ON DELETE NO ACTION
    ON UPDATE NO ACTION)
ENGINE = InnoDB;

-- -----------------------------------------------------
-- Table am_abisleri.Resident_has_Transport
-- -----------------------------------------------------
CREATE TABLE IF NOT EXISTS am_abisleri.Resident_has_Transport (
  Resident_Resident_ID VARCHAR(45) NOT NULL,
  Transport_Vehicle_ID INT NOT NULL,
  PRIMARY KEY (Resident_Resident_ID, Transport_Vehicle_ID),
  CONSTRAINT fk_Resident_has_Transport_Resident
    FOREIGN KEY (Resident_Resident_ID)
    REFERENCES am_abisleri.Resident (Resident_ID)
    ON DELETE NO ACTION
    ON UPDATE NO ACTION,
  CONSTRAINT fk_Resident_has_Transport_Transport
    FOREIGN KEY (Transport_Vehicle_ID)
    REFERENCES am_abisleri.Public_Transport (Vehicle_ID)
    ON DELETE NO ACTION
    ON UPDATE NO ACTION)
ENGINE = InnoDB;


-- -----------------------------------------------------
-- Table am_abisleri.Resident_has_Amenity
-- -----------------------------------------------------
CREATE TABLE IF NOT EXISTS am_abisleri.Resident_has_Amenity (
  Amenity_Amenity_ID INT NOT NULL,
  Resident_Resident_ID VARCHAR(45) NOT NULL,
  PRIMARY KEY (Amenity_Amenity_ID, Resident_Resident_ID),
  CONSTRAINT fk_Amenity_has_Resident_Amenity
    FOREIGN KEY (Amenity_Amenity_ID)
    REFERENCES am_abisleri.Amenity (Amenity_ID)
    ON DELETE NO ACTION
    ON UPDATE NO ACTION,
  CONSTRAINT fk_Amenity_has_Resident_Resident
    FOREIGN KEY (Resident_Resident_ID)
    REFERENCES am_abisleri.Resident (Resident_ID)
    ON DELETE NO ACTION
    ON UPDATE NO ACTION)
ENGINE = InnoDB;

