-- Stored Procedures
#PROCEDURE 1
DELIMITER $$
CREATE PROCEDURE Get_Avg_Complaints_By_Street(IN street_name VARCHAR(255))
BEGIN
    SELECT 
        COUNT(*) AS Total_Complaints,
        AVG(Process_time) AS Avg_Process_Time
    FROM 
        am_abisleri.Complaint
    WHERE 
        Description LIKE CONCAT('%', street_name, '%');
END $$
DELIMITER ;
CALL Get_Avg_Complaints_By_Street('Pinehurst Street');

#PROCEDURE 2
DELIMITER $$
CREATE PROCEDURE Get_Avg_Utilities_Per_Person_By_Residence_Type(IN people INT)
BEGIN
    SELECT Type AS Residence_Type,
           AVG(No_of_People) AS Average_People,
           AVG(Utilities / No_of_People) AS Avg_Utilities_Per_Person
    FROM am_abisleri.Residence
    WHERE No_of_People >= people
    GROUP BY Type;
END $$
DELIMITER ;
CALL Get_Avg_Utilities_Per_Person_By_Residence_Type(3);

#PROCEDURE 3
DELIMITER //
CREATE PROCEDURE GetHighTaxPayers()
BEGIN
    SELECT ‘BusinessID’, Type, Tax
    FROM am_abisleri.Business
    WHERE Tax > (SELECT AVG(Tax) FROM am_abisleri.Business)
    ORDER BY Tax DESC;
END //
DELIMITER ;
CALL GetHighTaxPayers();


